using Dapper; using Valora.Application.Contracts; using Valora.Application.DTOs; using Valora.Infrastructure.Database;
namespace Valora.Infrastructure.Repositories;
public sealed class OrganizationRepository(IDbConnectionFactory f):IOrganizationRepository{ public async Task<dynamic?> GetAsync(Guid id){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT id,name,public_name,email,phone,document,status,plan_id FROM valora.organizations WHERE id=@id AND is_deleted=false",new{id});} public async Task<Guid> CreateAsync(string name,string email,string slug,string planId){using var c=f.Create(); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valora.organizations(name,public_name,email,slug,plan_id) VALUES (@name,@name,@email,@slug,@planId) RETURNING id",new{name,email,slug,planId});} public async Task UpdateCurrentAsync(Guid id,UpdateOrganizationRequest r){using var c=f.Create(); await c.ExecuteAsync("UPDATE valora.organizations SET public_name=COALESCE(@PublicName,public_name), phone=COALESCE(@Phone,phone), document=COALESCE(@Document,document), updated_at=now() WHERE id=@id",new{r.PublicName,r.Phone,r.Document,id});} public async Task<int> CountManagersAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valora.users WHERE organization_id=@organizationId AND is_deleted=false AND status='active'",new{organizationId});}}
public sealed class UserRepository(IDbConnectionFactory f):IUserRepository{ public async Task<dynamic?> GetByEmailAsync(string email){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT * FROM valora.users WHERE lower(email)=lower(@email) AND is_deleted=false",new{email});} public async Task<dynamic?> GetAsync(Guid id){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT id,organization_id,name,email,role,status FROM valora.users WHERE id=@id",new{id});} public async Task<Guid> CreateAsync(Guid organizationId,string name,string email,string passwordHash,string role){using var c=f.Create(); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valora.users(organization_id,name,email,password_hash,role) VALUES (@organizationId,@name,@email,@passwordHash,@role) RETURNING id",new{organizationId,name,email,passwordHash,role});} public async Task TouchLoginAsync(Guid id){using var c=f.Create(); await c.ExecuteAsync("UPDATE valora.users SET last_login_at=now() WHERE id=@id",new{id});}}
public sealed class PlanRepository(IDbConnectionFactory f):IPlanRepository{ public async Task<IReadOnlyList<PlanDto>> GetPublicPlansAsync(){using var c=f.Create(); var plans=(await c.QueryAsync<dynamic>("SELECT * FROM billing.plans WHERE visible_on_public_pricing=true AND status='active' ORDER BY display_order")).ToList(); var result=new List<PlanDto>(); foreach(var p in plans) result.Add(await Hydrate((string)p.id,p)); return result;} public async Task<PlanDto?> GetByIdAsync(string id){using var c=f.Create(); var p=await c.QuerySingleOrDefaultAsync<dynamic>("SELECT * FROM billing.plans WHERE id=@id",new{id}); return p is null?null:await Hydrate(id,p);} async Task<PlanDto> Hydrate(string id,dynamic p){using var c=f.Create(); var limits=(await c.QueryAsync<(string limit_key,int limit_value)>("SELECT limit_key,limit_value FROM billing.plan_limits WHERE plan_id=@id",new{id})).ToDictionary(x=>x.limit_key,x=>x.limit_value); var caps=(await c.QueryAsync<(string capability_key,string capability_level)>("SELECT capability_key,capability_level FROM billing.plan_capabilities WHERE plan_id=@id",new{id})).ToDictionary(x=>x.capability_key,x=>x.capability_level); return new(id,(string)p.name,(string?)p.badge,(string)p.price_label,(string?)p.price_complement,(int)p.display_order,limits,caps);} public async Task<string?> GetCurrentPlanIdAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<string?>("SELECT plan_id FROM billing.subscriptions WHERE organization_id=@organizationId AND status='active' ORDER BY created_at DESC LIMIT 1",new{organizationId});} public async Task CreateSubscriptionAsync(Guid organizationId,string planId){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO billing.subscriptions(organization_id,plan_id) VALUES (@organizationId,@planId)",new{organizationId,planId});}}
public sealed class SurveyRepository(IDbConnectionFactory f):ISurveyRepository,IResponseRepository{ public async Task<dynamic?> GetPublicByTokenAsync(string token){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT id,title,description,status,expires_at FROM valora.surveys WHERE token_hash=@token AND is_deleted=false",new{token});} public async Task<Guid> SaveResponseAsync(Guid surveyId,SubmitResponseRequest r){using var c=f.Create(); var s=await c.QuerySingleAsync<dynamic>("SELECT organization_id,form_id FROM valora.surveys WHERE id=@surveyId",new{surveyId}); return await c.ExecuteScalarAsync<Guid>("INSERT INTO valora.responses(organization_id,survey_id,form_id,participant_name,participant_email,completed_at) VALUES (@organization_id,@surveyId,@form_id,@ParticipantName,@ParticipantEmail,now()) RETURNING id",new{s.organization_id,s.form_id,surveyId,r.ParticipantName,r.ParticipantEmail});} public async Task<dynamic?> GetResultAsync(Guid responseId){using var c=f.Create(); return await c.QuerySingleOrDefaultAsync("SELECT r.id,r.participant_name,rs.total_score,rs.percentage,rs.maturity_label FROM valora.responses r LEFT JOIN valora.result_scores rs ON rs.response_id=r.id WHERE r.id=@responseId",new{responseId});} public async Task<int> CountActiveSurveysAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valora.surveys WHERE organization_id=@organizationId AND status='active' AND is_deleted=false",new{organizationId});} public async Task<int> CountResponsesThisMonthAsync(Guid organizationId){using var c=f.Create(); return await c.ExecuteScalarAsync<int>("SELECT count(*) FROM valora.responses WHERE organization_id=@organizationId AND created_at >= date_trunc('month', now()) AND is_deleted=false",new{organizationId});}}
public sealed class AuditRepository(IDbConnectionFactory f):IAuditRepository{ public async Task AddAsync(AuditEntry e){using var c=f.Create(); await c.ExecuteAsync("INSERT INTO audit.audit_logs(organization_id,user_id,action,entity_type,entity_id,message,metadata_json) VALUES (@OrganizationId,@UserId,@Action,@EntityType,@EntityId,@Message,CAST(@MetadataJson AS jsonb))",e);}}
